package com.chaobo.scm.supplier.interfaces.web;
import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.item.SupplierItemHistoryQueryApplicationService;import jakarta.servlet.http.*;import jakarta.validation.constraints.*;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/supplier/v1")public class SupplierItemHistoryController {private final SupplierItemHistoryQueryApplicationService service;public SupplierItemHistoryController(SupplierItemHistoryQueryApplicationService service){this.service=service;}@GetMapping("/items/{itemId}/condition-history")public ApiResponse<List<SupplierItemHistoryQueryApplicationService.Condition>> conditions(@PathVariable long itemId,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ApiResponse.success(service.conditions(itemId,scope(jwt)),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}@GetMapping("/suppliers/{supplierId}/skus/{skuCode}/price-snapshots")public ApiResponse<List<SupplierItemHistoryQueryApplicationService.Price>> prices(@PathVariable long supplierId,@PathVariable @NotBlank String skuCode,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ApiResponse.success(service.prices(supplierId,skuCode,scope(jwt)),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}private Long scope(Jwt jwt){Number n=jwt.hasClaim("supplier_id")?jwt.getClaim("supplier_id"):null;return n==null?null:n.longValue();}}
